import{_ as e,o as r,c as a,a4 as o}from"./chunks/framework.DiadTcoQ.js";const g=JSON.parse('{"title":"Alphabet et prononciation","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/alphabet-pronunciation.md","filePath":"module-1/alphabet-pronunciation.md"}'),n={name:"module-1/alphabet-pronunciation.md"};function d(s,t,l,i,c,u){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="alphabet-et-prononciation" tabindex="-1">Alphabet et prononciation <a class="header-anchor" href="#alphabet-et-prononciation" aria-label="Permalink to “Alphabet et prononciation”">​</a></h1><p>L&#39;alphabet espagnol comporte 27 lettres — les 26 lettres latines plus le <strong>ñ</strong>. La bonne nouvelle : l&#39;espagnol se prononce comme il s&#39;écrit. Une fois les sons maîtrisés, tu peux lire n&#39;importe quel mot.</p><h2 id="les-lettres-particulieres" tabindex="-1">Les lettres particulières <a class="header-anchor" href="#les-lettres-particulieres" aria-label="Permalink to “Les lettres particulières”">​</a></h2><table tabindex="0"><thead><tr><th>Lettre</th><th>Nom</th><th>Prononciation</th><th>Exemple</th></tr></thead><tbody><tr><td><strong>ñ</strong></td><td>eñe</td><td>comme « gn » en français</td><td>España, mañana</td></tr><tr><td><strong>ll</strong></td><td>elle</td><td>comme « y »</td><td>llamar, lluvia</td></tr><tr><td><strong>rr</strong></td><td>erre doble</td><td>r roulé fort</td><td>perro, tierra</td></tr><tr><td><strong>j</strong></td><td>jota</td><td>comme « j » allemand, souffle fort</td><td>jamón, jugar</td></tr><tr><td><strong>h</strong></td><td>hache</td><td>toujours muet</td><td>hola, hacer</td></tr><tr><td><strong>v</strong></td><td>uve</td><td>identique au <strong>b</strong></td><td>vino, vivir</td></tr><tr><td><strong>z</strong></td><td>zeta</td><td>comme « s » en Amérique latine, « th » en Espagne</td><td>zapato, plaza</td></tr><tr><td><strong>c</strong></td><td>ce</td><td>doux devant e/i (« s »/« th »), dur ailleurs (« k »)</td><td>ciudad, casa</td></tr><tr><td><strong>g</strong></td><td>ge</td><td>doux devant a/o/u (« g »), souffle fort devant e/i</td><td>gato, gente</td></tr><tr><td><strong>qu</strong></td><td>cu</td><td>toujours « k », le u ne se prononce pas</td><td>queso, quiero</td></tr></tbody></table><h2 id="les-voyelles" tabindex="-1">Les voyelles <a class="header-anchor" href="#les-voyelles" aria-label="Permalink to “Les voyelles”">​</a></h2><p>Les voyelles espagnoles sont courtes et pures — pas de diphtongues comme en anglais.</p><table tabindex="0"><thead><tr><th>Lettre</th><th>Son</th><th>Exemple</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>« a » ouvert</td><td>casa</td></tr><tr><td><strong>e</strong></td><td>« é » fermé</td><td>mesa</td></tr><tr><td><strong>i</strong></td><td>« i »</td><td>libro</td></tr><tr><td><strong>o</strong></td><td>« o » fermé</td><td>foto</td></tr><tr><td><strong>u</strong></td><td>« ou »</td><td>mucho</td></tr></tbody></table><h2 id="les-accents" tabindex="-1">Les accents <a class="header-anchor" href="#les-accents" aria-label="Permalink to “Les accents”">​</a></h2><p>L&#39;accent aigu ( <strong>´</strong> ) indique la syllabe tonique quand elle ne suit pas la règle générale, ou distingue deux mots identiques.</p><table tabindex="0"><thead><tr><th>Règle</th><th>Exemple</th></tr></thead><tbody><tr><td>Mot terminé en voyelle, -n ou -s → avant-dernière syllabe</td><td>ca-sa, jo-ven</td></tr><tr><td>Mot terminé en consonne (sauf -n/-s) → dernière syllabe</td><td>ha-blar, ciu-dad</td></tr><tr><td>Accent écrit = exception à la règle</td><td>café,ación, árbol</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><strong>él</strong> (il) vs <strong>el</strong> (le) — l&#39;accent distingue le pronom de l&#39;article.</p></div><h2 id="entrainement" tabindex="-1">Entraînement <a class="header-anchor" href="#entrainement" aria-label="Permalink to “Entraînement”">​</a></h2><p>Lis ces mots à voix haute :</p><ul><li><strong>mañana</strong> — demain</li><li><strong>llover</strong> — pleuvoir</li><li><strong>hijo</strong> — fils</li><li><strong>querer</strong> — vouloir</li><li><strong>perro</strong> — chien</li><li><strong>zapato</strong> — chaussure</li></ul>',14)])])}const p=e(n,[["render",d]]);export{g as __pageData,p as default};
